import{_ as e,o as a,c as d,ag as o}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Default | Dotfiles (IT)","titleTemplate":":title","description":"Alias shell essenziali per navigazione, controllo sistema e attivita quotidiane. Semplifica il tuo flusso di lavoro nel terminale con queste scorciatoie universali.","frontmatter":{"title":"Alias Default | Dotfiles","description":"Alias shell essenziali per navigazione, controllo sistema e attivita quotidiane. Semplifica il tuo flusso di lavoro nel terminale con queste scorciatoie universali.","lang":"it-IT","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Default preview","canonical":"/it/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Default","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Default - Dotfiles (IT)","permalink":"/it/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"alias predefiniti, alias shell, scorciatoie terminale, dotfiles, alias bash"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Default - Dotfiles"},{"name":"twitter:description","content":"Alias shell essenziali per navigazione, controllo sistema e attivita quotidiane."},{"name":"og:title","content":"Alias Default - Dotfiles"},{"name":"og:description","content":"Alias shell essenziali per navigazione, controllo sistema e attivita quotidiane."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"it_IT"}]},"headers":[],"relativePath":"it/aliases/default/index.md","filePath":"it/aliases/default/index.md","lastUpdated":1773010926000}'),i={name:"it/aliases/default/index.md"};function l(r,t,c,s,n,h){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="alias-default" tabindex="-1">Alias Default <a class="header-anchor" href="#alias-default" aria-label="Permalink to &quot;Alias Default&quot;">​</a></h1><p>Scorciatoie shell essenziali per le attivita quotidiane del terminale.</p><h2 id="panoramica" tabindex="-1">Panoramica <a class="header-anchor" href="#panoramica" aria-label="Permalink to &quot;Panoramica&quot;">​</a></h2><p>Gli alias default forniscono una collezione di scorciatoie shell universali che semplificano le operazioni comuni del terminale. Questi alias sono definiti in <code>default.aliases.sh</code> e caricati automaticamente da chezmoi su tutte le shell supportate.</p><p>Queste scorciatoie coprono utility generali, comandi di uscita, diagnostica di rete, monitoraggio sistema e navigazione del file system.</p><h2 id="riferimento" tabindex="-1">Riferimento <a class="header-anchor" href="#riferimento" aria-label="Permalink to &quot;Riferimento&quot;">​</a></h2><h3 id="generale" tabindex="-1">Generale <a class="header-anchor" href="#generale" aria-label="Permalink to &quot;Generale&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>da</code></td><td><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td>Visualizza data e ora correnti</td></tr><tr><td><code>p</code></td><td><code>pwd</code></td><td>Stampa directory di lavoro</td></tr><tr><td><code>path</code></td><td><code>echo ${PATH//:/\\\\n}</code></td><td>Visualizza variabile PATH su nuove righe</td></tr><tr><td><code>r</code></td><td><code>reload</code></td><td>Ricarica la shell</td></tr><tr><td><code>t</code></td><td><code>tail -f</code></td><td>Segui output file in tempo reale</td></tr><tr><td><code>wk</code></td><td><code>date +%V</code></td><td>Mostra numero settimana corrente</td></tr></tbody></table><h3 id="uscita-e-spegnimento" tabindex="-1">Uscita e spegnimento <a class="header-anchor" href="#uscita-e-spegnimento" aria-label="Permalink to &quot;Uscita e spegnimento&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>q</code></td><td><code>exit</code></td><td>Esci dalla shell</td></tr><tr><td><code>quit</code></td><td><code>exit</code></td><td>Esci dalla shell</td></tr><tr><td><code>bye</code></td><td><code>exit</code></td><td>Esci dalla shell</td></tr><tr><td><code>:q</code></td><td><code>exit</code></td><td>Esci dalla shell (stile vim)</td></tr><tr><td><code>halt</code></td><td><code>sudo /sbin/halt</code></td><td>Arresta il sistema</td></tr><tr><td><code>poweroff</code></td><td><code>sudo /sbin/shutdown</code></td><td>Spegni il sistema</td></tr><tr><td><code>reboot</code></td><td><code>sudo /sbin/reboot</code></td><td>Riavvia il sistema</td></tr></tbody></table><h3 id="cronologia" tabindex="-1">Cronologia <a class="header-anchor" href="#cronologia" aria-label="Permalink to &quot;Cronologia&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>h</code></td><td><code>history</code></td><td>Visualizza cronologia comandi</td></tr><tr><td><code>history</code></td><td><code>fc -il 1</code></td><td>Mostra cronologia con timestamp ISO 8601</td></tr></tbody></table><h3 id="rete" tabindex="-1">Rete <a class="header-anchor" href="#rete" aria-label="Permalink to &quot;Rete&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>ifconfig</code></td><td><code>sudo ifconfig</code></td><td>Configura interfacce di rete</td></tr><tr><td><code>ipinfo</code></td><td><code>ipconfig getpacket en0</code></td><td>Ottieni parametri rete per en0</td></tr><tr><td><code>nls</code></td><td><code>sudo lsof -i -P | grep LISTEN</code></td><td>Mostra listener di rete attivi</td></tr><tr><td><code>op</code></td><td><code>sudo lsof -i -P</code></td><td>Elenca porte aperte</td></tr><tr><td><code>ping</code></td><td><code>ping -c 5</code></td><td>Ping con limite 5 pacchetti</td></tr><tr><td><code>ports</code></td><td><code>netstat -tulan</code></td><td>Elenca tutte le porte in ascolto</td></tr></tbody></table><h3 id="monitoraggio-sistema" tabindex="-1">Monitoraggio sistema <a class="header-anchor" href="#monitoraggio-sistema" aria-label="Permalink to &quot;Monitoraggio sistema&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>top</code></td><td><code>sudo btop</code></td><td>Monitor processi interattivo</td></tr><tr><td><code>spd</code></td><td><code>sudo rm -rf /private/var/log/asl/*</code></td><td>Pulisci file log ASL</td></tr></tbody></table><h3 id="utility" tabindex="-1">Utility <a class="header-anchor" href="#utility" aria-label="Permalink to &quot;Utility&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>ctf</code></td><td><code>ls -1 | wc -l</code></td><td>Conta file nella directory corrente</td></tr><tr><td><code>qfind</code></td><td><code>find . -name</code></td><td>Ricerca file rapida</td></tr><tr><td><code>reload</code></td><td><code>exec $SHELL -l</code></td><td>Ricarica la shell</td></tr><tr><td><code>wth</code></td><td><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td>Ottieni meteo corrente</td></tr></tbody></table>',18)])])}const f=e(i,[["render",l]]);export{m as __pageData,f as default};
